public int[] intervalIntersection(int[][] intervals) {

    PriorityQueue<Integer> pq= new PriorityQueue<>((a,b)->a-b);

    for(int[] interval: intervals){
        pq.add(interval[0]);
    }
    int k=1;

    TreeMap<Integer,int[]> res= new TreeMap<>();
    for(int i=0;i<intervals.length;i++){
        if(k<intervals.length && intervals[i][1]>intervals[k][0]){
            int diff =intervals[i][1]- intervals[k][0];
        res.put(diff, new int[]{intervals[k][0], intervals[i][1] });
        }
        k++;
    }

    return res.get(res.lastKey());
}

public class DriverInterval {

	public static void main(String[] args) {
		int[][] nums = { { 1, 5 }, { 10, 16 }, { 2, 7 }, { 100, 120 } };
		Interval intl = maxInterval(nums);
		if (intl == null) {
			System.out.println("N/A");
		} else {
			System.out.println("[" + intl.getStart() + "," + intl.getEnd() + "]");
		}

	}

	private static Interval maxInterval(int[][] nums) {

		int n = nums.length;
		int maxDiff = Integer.MIN_VALUE;
		Interval maxInterval = null;

		Interval[] intervals = new Interval[n];

		for (int i = 0; i < n; i++) {
			intervals[i] = new Interval(nums[i][0], nums[i][1]);
		}

		Arrays.sort(intervals, (a, b) -> (a.getStart() - b.getStart()));

		PriorityQueue<Integer> pq = new PriorityQueue<>((a, b) -> (b - a));
		pq.offer(intervals[0].getEnd());

		for (int i = 1; i < n; i++) {
			Interval intl = intervals[i];

			// nextstart > last end
			if (intl.getStart() > pq.peek()) {
				if (intl.getStart() - pq.peek() > maxDiff) {
					maxDiff = intl.getStart() - pq.peek();
					maxInterval = new Interval(pq.peek(), intl.getStart());
				}

				pq.offer(intl.getEnd());
			}
		}

		return maxInterval;
	}
}
public class Interval {

	private int start;
	private int end;

	public Interval(int start, int end) {
		super();
		this.start = start;
		this.end = end;
	}

	public int getStart() {
		return start;
	}

	public void setStart(int start) {
		this.start = start;
	}

	public int getEnd() {
		return end;
	}

	public void setEnd(int end) {
		this.end = end;
	}

}
